+      user: { id: params.userId ?? "U1", name: params.userName ?? "Ada" },
+      channel: { id: params.channelId ?? "C1", name: params.channelName ?? "directmessage" },
+      trigger_id: "t1",
+    },
+  };
+  if (includeRespond) {
+    payload.respond = respond;
+  }
+  await handler(payload);
+  return respond;
+}
